#include <stdio.h>
#include <string.h>
#include <stdlib.h>

/*
 * Basic XOR Encryption Simulation
 * Note: XOR encryption is NOT secure for production use.
 * This demonstrates the concept of symmetric encryption used in TLS.
 */

void xor_encrypt(char *data, const char *key, size_t data_len) {
 size_t key_len = strlen(key);

 for (size_t i = 0; i < data_len; i++) {
 // XOR each byte with key byte (cycling through key)
 data[i] = data[i] ^ key[i % key_len];
 }
}

void print_hex(const char *label, const char *data, size_t len) {
 printf("%s: ", label);
 for (size_t i = 0; i < len; i++) {
 printf("%02x ", (unsigned char)data[i]);
 }
 printf("\n");
}

int main() {
 // Simulating confidential data (e.g., password, credit card)
 const char *original_message = "SECRET_PASSWORD_123";
 const char *key = "TLS_KEY";

 size_t msg_len = strlen(original_message) + 1; // +1 for null terminator

 // Allocate memory for encrypted data
 char *encrypted = (char *)malloc(msg_len);
 char *decrypted = (char *)malloc(msg_len);

 if (!encrypted || !decrypted) {
 printf("Memory allocation failed\n");
 return 1;
 }

 // Copy original message
 memcpy(encrypted, original_message, msg_len);

 printf("=== Web Security: Data Confidentiality Demo ===\n\n");

 // Show original data (in real TLS, this would be plaintext)
 printf("Before encryption (confidentiality):\n");
 printf(" Plaintext: %s\n\n", original_message);

 // ENCRYPT (confidentiality)
 xor_encrypt(encrypted, key, msg_len);
 print_hex("Encrypted", encrypted, msg_len);
 printf(" (This is what an eavesdropper sees on the network)\n\n");

 // DECRYPT (simulating receiver with the key)
 memcpy(decrypted, encrypted, msg_len);
 xor_encrypt(decrypted, key, msg_len);

 printf("After decryption (receiver side):\n");
 printf(" Plaintext: %s\n\n", decrypted);

 // Demonstrate integrity check (simple version)
 printf("=== Integrity Verification ===\n");
 if (strcmp(original_message, decrypted) == 0) {
 printf("Integrity check PASSED: Data was not modified\n");
 } else {
 printf("Integrity check FAILED: Data was modified!\n");
 }

 // Show what attacker sees if they try to modify data
 printf("\n=== Active Attack Demo ===\n");
 encrypted[5] ^= 0xFF; // Tamper with encrypted data
 print_hex("Tampered", encrypted, msg_len);

 memcpy(decrypted, encrypted, msg_len);
 xor_encrypt(decrypted, key, msg_len);
 printf("After decryption: %s\n", decrypted);

 if (strcmp(original_message, decrypted) != 0) {
 printf("Integrity check FAILED: Attack detected!\n");
 }

 free(encrypted);
 free(decrypted);

 return 0;
}

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.util.Base64;

/**
 * HMAC (Hash-based Message Authentication Code) Implementation
 * 
 * In TLS, HMAC provides:
 * - Integrity: Verify message wasn't modified
 * - Authentication: Verify message came from the claimed sender
 * 
 * This demonstrates the cryptographic building block used in TLS handshake
 */
public class HMACAuthenticator {

 private static final String HMAC_ALGORITHM = "HmacSHA256";

 /**
 * Generate HMAC for a message using a secret key
 * This provides integrity and authentication
 */
 public static String generateHMAC(String message, String secretKey) throws Exception {
 // Create SecretKeySpec for HMAC
 SecretKeySpec keySpec = new SecretKeySpec(
 secretKey.getBytes(), 
 HMAC_ALGORITHM
 );

 // Initialize HMAC algorithm
 Mac hmac = Mac.getInstance(HMAC_ALGORITHM);
 hmac.init(keySpec);

 // Compute HMAC
 byte[] hmacBytes = hmac.doFinal(message.getBytes());

 // Return as Base64 for easy transmission
 return Base64.getEncoder().encodeToString(hmacBytes);
 }

 /**
 * Verify HMAC - used to check message integrity
 */
 public static boolean verifyHMAC(
 String message, 
 String receivedHMAC, 
 String secretKey
 ) throws Exception {
 String computedHMAC = generateHMAC(message, secretKey);
 return computedHMAC.equals(receivedHMAC);
 }

 public static void main(String[] args) {
 try {
 String message = "Transfer $1000 to account 12345";
 String sharedSecret = "MySecureTLSSecretKey";

 System.out.println("=== Web Security: HMAC Authentication Demo ===\n");

 // Sender generates HMAC
 String hmac = generateHMAC(message, sharedSecret);
 System.out.println("Original Message: " + message);
 System.out.println("Generated HMAC: " + hmac);
 System.out.println();

 // Receiver verifies HMAC (valid case)
 boolean isValid = verifyHMAC(message, hmac, sharedSecret);
 System.out.println("Verification (untampered): " + (isValid ? "SUCCESS" : "FAILED"));
 System.out.println();

 // Attacker tampers with message
 String tamperedMessage = "Transfer $9999 to account 99999";
 System.out.println("=== Active Attack Simulation ===\n");
 System.out.println("Attacker modified message to: " + tamperedMessage);

 // Verify fails because message changed
 boolean attackDetected = !verifyHMAC(tamperedMessage, hmac, sharedSecret);
 System.out.println("Attack detected: " + (attackDetected ? "YES" : "NO"));
 System.out.println();

 // Wrong key test
 String wrongKey = "WrongSecretKey";
 boolean wrongKeyTest = !verifyHMAC(message, hmac, wrongKey);
 System.out.println("Wrong key detected: " + (wrongKeyTest ? "YES" : "NO"));

 System.out.println("\n=== Security Properties Demonstrated ===");
 System.out.println("1. Integrity: HMAC changes if message changes");
 System.out.println("2. Authentication: Only parties with key can generate valid HMAC");
 System.out.println("3. Non-repudiation: Message authenticity can be proven to third parties");

 } catch (Exception e) {
 System.err.println("Error: " + e.getMessage());
 }
 }
}
